#include<bits/stdc++.h>
using namespace std;
const int N = 3e5+5;
int n,q,A[N],B[N],num[N],tmp[N],now;
bool flag;
int main(){
	cin>>n>>q;
	while(q--){
		int s,t;cin>>s>>t;
		if(s==t)continue;
		if(s<t)A[s-1]++,A[t-1]--;
		else B[t]++,B[s]--;
	}
	for(int i=1;i<=n;i++)A[i]+=A[i-1],B[i]+=B[i-1];
	for(int i=1;i<=n;i++)if(A[i]&&B[i])flag=1;
	if(flag){cout<<"QED";return 0;}
	for(int i=1;i<=n;i++){
		if(!num[i]){
			int cnt=1;tmp[1]=i;
			for(int j=i;A[j]&&j+2<=n;j+=2)tmp[++cnt]=j+2;
			for(int j=cnt;j>=1;j--)num[tmp[j]]=++now;
		}
	}
	for(int i=1;i<=n;i++)cout<<num[i]<<" ";
	return 0;
}
